// 1. Create a lookup for folders by ID
const folderMap = {};
for (const item of items) {
  folderMap[item.json.folderId] = item.json;
}

// 2. Recursive function to build full path
function buildFullPath(folder) {
  if (!folder.parentFolderId || folder.parentFolderId === 'null') {
    return folder['folderName'];
  }

  const parent = folderMap[folder.parentFolderId];
  if (!parent) {
    return folder['folderName']; // Edge case: parent missing
  }

  return `${buildFullPath(parent)}/${folder['folderName']}`;
}

// 3. Loop over all folders and generate full_path
return items.map(item => {
  const folder = item.json;
  folder.full_path = buildFullPath(folder);
  return { json: folder };
});

